blocks.body:
{
    "level": "B1–B2",
    "intro": "W tym temacie poznasz <strong>bardziej zaawansowane struktury emfatyczne</strong>: inwersję po wyrażeniach negatywnych, zdania typu <strong>it-cleft</strong> i <strong>what-cleft</strong> oraz emphatic <strong>do</strong>.",
    "rules": [
        {
            "label": "Inversion",
            "color": "emerald",
            "text": "Po niektórych wyrażeniach negatywnych zmienia się szyk zdania: <strong>Auxiliary + Subject</strong>.",
            "example": "Never have I seen such beauty."
        },
        {
            "label": "It-cleft",
            "color": "blue",
            "text": "Struktura <strong>It was / is ... who / that</strong> podkreśla konkretny element zdania.",
            "example": "It was you who invited me."
        },
        {
            "label": "What-cleft",
            "color": "amber",
            "text": "Struktura <strong>What ... is / was</strong> podkreśla czynność albo rzecz.",
            "example": "What I need is some rest."
        }
    ]
}

{
    "title": "1. Kiedy używać struktur emfatycznych",
    "intro": "Takie konstrukcje pomagają, gdy chcesz:",
    "items": [
        {
            "label": "1",
            "title": "Wyraźnie coś podkreślić",
            "subtitle": "Na przykład kto coś zrobił, kiedy to się stało albo co jest najważniejsze."
        },
        {
            "label": "2",
            "title": "Brzmieć bardziej formalnie",
            "subtitle": "Często pojawiają się w języku pisanym, prezentacjach i bardziej oficjalnym stylu."
        },
        {
            "label": "3",
            "title": "Zbudować kontrast",
            "subtitle": "Są przydatne, gdy coś poprawiasz, doprecyzowujesz albo zestawiasz ze sobą dwie informacje."
        }
    ]
}

{
    "title": "2. Inwersja po wyrażeniach negatywnych",
    "sections": [
        {
            "label": "Jak działa inwersja",
            "color": "emerald",
            "description": "Jeśli zdanie zaczyna się od <strong>negative adverbial</strong>, szyk staje się bardziej formalny i pojawia się inwersja: <strong>auxiliary + subject</strong>.",
            "examples": [
                {
                    "en": "Never have I seen such a beautiful sunset.",
                    "ua": "Nigdy nie widziałem tak pięknego zachodu słońca."
                },
                {
                    "en": "Rarely does she make mistakes.",
                    "ua": "Rzadko popełnia błędy."
                },
                {
                    "en": "Seldom do we get such opportunities.",
                    "ua": "Rzadko mamy takie okazje."
                }
            ]
        },
        {
            "label": "Not only ... but also",
            "color": "sky",
            "description": "Po <strong>Not only</strong> pierwsza część zdania wymaga inwersji.",
            "examples": [
                {
                    "en": "Not only did he finish early, but he also helped others.",
                    "ua": "Nie tylko skończył wcześniej, ale też pomógł innym."
                },
                {
                    "en": "Not only is she smart, but she is also kind.",
                    "ua": "Nie tylko jest inteligentna, ale też życzliwa."
                }
            ]
        },
        {
            "label": "Hardly / no sooner",
            "color": "amber",
            "description": "Te konstrukcje służą do znaczeń typu „ledwo... a już...” albo „dopiero co...”.",
            "examples": [
                {
                    "en": "Hardly had we arrived when it started raining.",
                    "ua": "Ledwo przyjechaliśmy, a już zaczęło padać."
                },
                {
                    "en": "No sooner had I sat down than the phone rang.",
                    "ua": "Dopiero co usiadłem, a telefon zadzwonił."
                }
            ],
            "note": "Po hardly / scarcely zwykle stoi <em>when</em>, a po no sooner — <em>than</em>."
        }
    ]
}

{
    "title": "3. It-cleft sentences",
    "sections": [
        {
            "label": "Podkreślenie osoby",
            "color": "emerald",
            "description": "Struktura <strong>It was / is + osoba + who</strong> podkreśla, kto wykonał czynność.",
            "examples": [
                {
                    "en": "You invited me. → It was you who invited me.",
                    "ua": "To właśnie ty mnie zaprosiłeś."
                },
                {
                    "en": "She broke the vase. → It was she who broke the vase.",
                    "ua": "To właśnie ona stłukła wazon."
                },
                {
                    "en": "John called. → It was John who called.",
                    "ua": "To właśnie John zadzwonił."
                }
            ]
        },
        {
            "label": "Akcent w zdaniu",
            "color": "sky",
            "description": "Gdy podkreślasz nie osobę, tylko czas, miejsce lub inną część zdania, zwykle używasz <strong>that</strong>.",
            "examples": [
                {
                    "en": "She left yesterday. → It was yesterday that she left.",
                    "ua": "To właśnie wczoraj wyjechała."
                },
                {
                    "en": "I need help. → It is help that I need.",
                    "ua": "To właśnie pomocy potrzebuję."
                },
                {
                    "en": "We met in Paris. → It was in Paris that we met.",
                    "ua": "To właśnie w Paryżu się poznaliśmy."
                }
            ],
            "note": "Who najczęściej odnosi się do osób, a that do pozostałych elementów."
        }
    ]
}

{
    "title": "4. What-cleft sentences",
    "sections": [
        {
            "label": "Podstawowa struktura",
            "color": "emerald",
            "description": "<strong>What + clause + is / was + emphasized element</strong> pozwala podkreślić rzecz, czynność albo rezultat.",
            "examples": [
                {
                    "en": "I need rest. → What I need is some rest.",
                    "ua": "Tym, czego potrzebuję, jest trochę odpoczynku."
                },
                {
                    "en": "I like the park. → What I like is the park.",
                    "ua": "To, co lubię, to ten park."
                },
                {
                    "en": "She wants a vacation. → What she wants is a vacation.",
                    "ua": "To, czego chce, to wakacje."
                }
            ]
        },
        {
            "label": "Inne warianty z wh-",
            "color": "sky",
            "description": "Podobny efekt można uzyskać także z <strong>where, why, who, how</strong>.",
            "examples": [
                {
                    "en": "Where I grew up is very far from here.",
                    "ua": "Miejsce, w którym dorastałem, jest bardzo daleko stąd."
                },
                {
                    "en": "Why she left is still a mystery.",
                    "ua": "Dlaczego wyjechała, wciąż pozostaje tajemnicą."
                },
                {
                    "en": "How he did it amazed everyone.",
                    "ua": "To, jak on to zrobił, zaskoczyło wszystkich."
                }
            ]
        }
    ]
}

{
    "title": "5. Fronting i emphatic do",
    "sections": [
        {
            "label": "Fronting",
            "color": "emerald",
            "description": "<strong>Fronting</strong> polega na przesunięciu ważnego elementu na początek zdania, żeby go mocniej zaakcentować.",
            "examples": [
                {
                    "en": "The kids left quickly. → Quickly the kids left.",
                    "ua": "Szybko dzieci wyszły."
                },
                {
                    "en": "I like this book very much. → This book I like very much.",
                    "ua": "Tę książkę bardzo lubię."
                },
                {
                    "en": "Away ran the children.",
                    "ua": "I dzieci pobiegły precz."
                }
            ],
            "note": "Fronting jest częstszy w literaturze i bardziej formalnym stylu niż w zwykłej codziennej rozmowie."
        },
        {
            "label": "Emphatic do / does / did",
            "color": "sky",
            "description": "W zdaniach twierdzących można użyć <strong>do / does / did</strong>, żeby coś szczególnie podkreślić.",
            "examples": [
                {
                    "en": "I like it. → I DO like it!",
                    "ua": "Naprawdę to lubię!"
                },
                {
                    "en": "She finished. → She DID finish her homework!",
                    "ua": "Ona naprawdę odrobiła pracę domową!"
                },
                {
                    "en": "He knows. → He DOES know the answer.",
                    "ua": "On naprawdę zna odpowiedź."
                }
            ],
            "note": "To częsty sposób na podkreślenie sprzeciwu, potwierdzenia albo emocji."
        }
    ]
}

{
    "title": "6. Wyrażenia uruchamiające inwersję",
    "intro": "Po tych wyrażeniach często pojawia się inwersja:",
    "rows": [
        {
            "en": "Never",
            "ua": "nigdy",
            "note": "Never have I..."
        },
        {
            "en": "Rarely / Seldom",
            "ua": "rzadko",
            "note": "Rarely does she..."
        },
        {
            "en": "Hardly / Scarcely",
            "ua": "ledwo",
            "note": "Hardly had we..."
        },
        {
            "en": "Not only",
            "ua": "nie tylko",
            "note": "Not only did he..."
        },
        {
            "en": "No sooner",
            "ua": "dopiero co",
            "note": "No sooner had I..."
        },
        {
            "en": "Only when / after / if",
            "ua": "dopiero kiedy / po / jeśli",
            "note": "Only when I arrived did I..."
        }
    ],
    "warning": "Jeśli w zdaniu nie ma jeszcze czasownika posiłkowego, trzeba zwykle dodać do / does / did."
}

{
    "title": "7. Typowe błędy",
    "items": [
        {
            "label": "Błąd 1",
            "color": "rose",
            "title": "Brak inwersji po wyrażeniu negatywnym.",
            "wrong": "Never I have seen...",
            "right": "✅ <span class=\"font-mono\">Never have I seen...<\/span>"
        },
        {
            "label": "Błąd 2",
            "color": "amber",
            "title": "Which zamiast who przy osobach w it-cleft.",
            "wrong": "It was you which invited me.",
            "right": "✅ <span class=\"font-mono\">It was you who invited me.<\/span>"
        },
        {
            "label": "Błąd 3",
            "color": "sky",
            "title": "Nienaturalny what-cleft.",
            "wrong": "What I need is to rest.",
            "right": "✅ <span class=\"font-mono\">What I need is some rest.<\/span>"
        },
        {
            "label": "Błąd 4",
            "color": "purple",
            "title": "Dodatkowe -s po emphatic do.",
            "wrong": "He do knows the answer.",
            "right": "✅ <span class=\"font-mono\">He does know the answer.<\/span>"
        }
    ]
}

{
    "title": "9. Ćwiczenia",
    "select_title": "Ćwiczenie 1. Wybierz poprawną opcję",
    "select_intro": "Wskaż zdanie z poprawną strukturą.",
    "selects": [
        {
            "label": "a) Never I have seen... / b) Never have I seen...",
            "prompt": "Która opcja jest poprawna?"
        },
        {
            "label": "a) It was you who invited me. / b) It was you which invited me.",
            "prompt": "Która opcja jest poprawna?"
        },
        {
            "label": "a) What I need is some rest. / b) What I need is to rest.",
            "prompt": "Która opcja jest poprawna?"
        }
    ],
    "options": [
        "a",
        "b"
    ],
    "input_title": "Ćwiczenie 2. Przekształć na it-cleft",
    "input_intro": "Podkreśl wskazany element za pomocą struktury it-cleft.",
    "inputs": [
        {
            "before": "YOU called me. →",
            "after": "It was..."
        },
        {
            "before": "She left YESTERDAY. →",
            "after": "It was..."
        },
        {
            "before": "I need HELP. →",
            "after": "It is..."
        }
    ],
    "rephrase_title": "Ćwiczenie 3. Dodaj inwersję",
    "rephrase_intro": "Przepisz zdanie, zaczynając od wskazanego wyrażenia negatywnego.",
    "rephrase": [
        {
            "example_label": "Przykład:",
            "example_original": "I have never seen such beauty.",
            "example_target": "Never have I seen such beauty."
        },
        {
            "original": "1. She rarely makes mistakes.",
            "placeholder": "Rarely..."
        },
        {
            "original": "2. He not only finished early, but also helped.",
            "placeholder": "Not only..."
        }
    ]
}

{
    "title": "Kontynuuj naukę",
    "items": [
        {
            "label": "Basic Word Order",
            "current": false
        },
        {
            "label": "Pytania i przeczenia",
            "current": false
        },
        {
            "label": "Przysłówki w zdaniu",
            "current": false
        },
        {
            "label": "Word Order with Verbs and Objects",
            "current": false
        },
        {
            "label": "Advanced Word Order / Emphasis",
            "current": true
        }
    ]
}
